import React from 'react';
import { Mail, Phone, Github, Linkedin, MapPin, Download } from 'lucide-react';
import { CONTACT, EDUCATION, SKILLS, EXPERIENCE, PROJECTS, CERTIFICATIONS, PROFESSIONAL_SKILLS } from '../data';

export default function ResumeView() {
    return (
        <div style={{
            height: '100%',
            width: '100%',
            background: 'var(--bg)',
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            padding: '2rem 1rem',
            overflowY: 'auto'
        }}>
            {/* Floating Download Button */}
            <div style={{
                position: 'fixed',
                left: '5%',
                top: '20%',
                zIndex: 10,
                display: 'none', // Hide on mobile
            }} className="desktop-download">
                <a
                    href={CONTACT.resume}
                    style={{
                        display: 'flex',
                        alignItems: 'center',
                        gap: '10px',
                        padding: '1rem 1.5rem',
                        background: '#ff4b5c',
                        color: '#fff',
                        borderRadius: '8px',
                        fontWeight: 700,
                        boxShadow: '0 4px 15px rgba(255, 75, 92, 0.3)',
                        transition: 'transform 0.2s'
                    }}
                    onMouseEnter={(e) => e.currentTarget.style.transform = 'scale(1.05)'}
                    onMouseLeave={(e) => e.currentTarget.style.transform = 'scale(1)'}
                >
                    <Download size={20} />
                    <span>Download Resume</span>
                </a>
            </div>

            {/* Resume Document */}
            <div style={{
                width: '100%',
                maxWidth: '850px',
                background: '#fff',
                color: '#333',
                padding: '3rem',
                boxShadow: '0 10px 40px rgba(0,0,0,0.5)',
                borderRadius: '2px',
                fontFamily: "'Inter', sans-serif",
                lineHeight: 1.5
            }} className="resume-document">

                {/* Header */}
                <header style={{ borderBottom: '2px solid #333', paddingBottom: '1.5rem', marginBottom: '2rem' }}>
                    <h1 style={{ fontSize: '2.5rem', fontWeight: 800, color: '#000', marginBottom: '0.5rem' }}>Sanjay.S</h1>
                    <p style={{ fontSize: '1.2rem', fontWeight: 600, color: '#555', marginBottom: '1rem' }}>MERN Stack Developer</p>

                    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '0.8rem', fontSize: '0.85rem' }}>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}><Linkedin size={14} /> linkedin.com/in/sanjay</div>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}><Mail size={14} /> {CONTACT.email}</div>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}><Github size={14} /> github.com/sanjay</div>
                        <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}><Phone size={14} /> {CONTACT.phone}</div>
                    </div>
                </header>

                {/* Section: Education */}
                <section style={{ marginBottom: '2rem' }}>
                    <h2 style={{ fontSize: '1rem', fontWeight: 800, background: '#f0f0f0', padding: '4px 10px', textAlign: 'center', textTransform: 'uppercase', letterSpacing: '0.1em', marginBottom: '1rem' }}>Education</h2>
                    {EDUCATION.map((edu, idx) => (
                        <div key={idx} style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.8rem' }}>
                            <div>
                                <p style={{ fontWeight: 700 }}>{edu.college}</p>
                                <p style={{ fontSize: '0.9rem', color: '#555' }}>{edu.degree}</p>
                            </div>
                            <div style={{ textAlign: 'right', fontSize: '0.9rem' }}>
                                <p>{edu.detail.split('·')[1] || 'Present'}</p>
                            </div>
                        </div>
                    ))}
                </section>

                {/* Section: Skills */}
                <section style={{ marginBottom: '2rem' }}>
                    <h2 style={{ fontSize: '1rem', fontWeight: 800, background: '#f0f0f0', padding: '4px 10px', textAlign: 'center', textTransform: 'uppercase', letterSpacing: '0.1em', marginBottom: '1rem' }}>Skills</h2>
                    {Object.entries(SKILLS).map(([cat, items]) => (
                        <p key={cat} style={{ fontSize: '0.9rem', marginBottom: '0.4rem' }}>
                            <span style={{ fontWeight: 700 }}>{cat}: </span> {items.join(', ')}
                        </p>
                    ))}
                </section>

                {/* Section: Experience/Internship */}
                <section style={{ marginBottom: '2rem' }}>
                    <h2 style={{ fontSize: '1rem', fontWeight: 800, background: '#f0f0f0', padding: '4px 10px', textAlign: 'center', textTransform: 'uppercase', letterSpacing: '0.1em', marginBottom: '1rem' }}>Internship</h2>
                    {EXPERIENCE.map((exp, idx) => (
                        <div key={idx} style={{ marginBottom: '1.2rem' }}>
                            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.4rem' }}>
                                <p style={{ fontWeight: 700 }}>{exp.role} | {exp.company}</p>
                                <p style={{ fontSize: '0.85rem', color: '#555' }}>{exp.period}</p>
                            </div>
                            <ul style={{ paddingLeft: '1.2rem', fontSize: '0.85rem' }}>
                                {exp.points.map((pt, i) => <li key={i} style={{ marginBottom: '3px' }}>{pt}</li>)}
                            </ul>
                        </div>
                    ))}
                </section>

                {/* Section: Projects */}
                <section style={{ marginBottom: '2rem' }}>
                    <h2 style={{ fontSize: '1rem', fontWeight: 800, background: '#f0f0f0', padding: '4px 10px', textAlign: 'center', textTransform: 'uppercase', letterSpacing: '0.1em', marginBottom: '1rem' }}>Projects</h2>
                    {PROJECTS.map((proj, idx) => (
                        <div key={idx} style={{ marginBottom: '1.2rem' }}>
                            <p style={{ fontWeight: 700, fontSize: '0.95rem' }}>{proj.title} ({proj.stack.join(', ')})</p>
                            <ul style={{ paddingLeft: '1.2rem', fontSize: '0.85rem', marginTop: '0.3rem' }}>
                                <li style={{ marginBottom: '3px' }}>{proj.desc}</li>
                            </ul>
                        </div>
                    ))}
                </section>

                {/* Section: Certifications */}
                <section style={{ marginBottom: '2rem' }}>
                    <h2 style={{ fontSize: '1rem', fontWeight: 800, background: '#f0f0f0', padding: '4px 10px', textAlign: 'center', textTransform: 'uppercase', letterSpacing: '0.1em', marginBottom: '1rem' }}>Certifications</h2>
                    <ul style={{ paddingLeft: '1.2rem', fontSize: '0.85rem' }}>
                        {CERTIFICATIONS.map((cert, i) => <li key={i} style={{ marginBottom: '3px' }}>{cert}</li>)}
                    </ul>
                </section>

                {/* Section: Professional Skills */}
